const root = $json.body || $json;
const event = root.event || $json.event || root;
const content = String(event.content || event.transcript || root.chatInput || root.message || root.text || '').trim();
if (!content) {
  throw new Error('Missing voice content');
}

return [{
  json: {
    ...event,
    userText: content,
    language: event.language || root.language || 'ar',
    channel: event.channel || root.channel || 'website_voice',
    source_label: event.source_label || root.source_label || 'website_voice',
    session_id: event.session_id || root.session_id || `voice-${Date.now()}`,
    event_ts: event.event_ts || event.timestamp || root.timestamp || new Date().toISOString()
  }
}];

const query = $fromAI('query', 'What service detail is the caller asking for', 'string');

const services = {
  automation: 'أنظمة أتمتة الأعمال: نربط أدواتك ونبني تدفق شغل يقلل الهدر والأخطاء ويوفر وقت الفريق.',
  crm: 'أنظمة CRM والمبيعات: نرتب المتابعة والمراحل البيعية ونقلل ضياع الفرص.',
  leads: 'توليد العملاء: نبني مسار واضح لالتقاط وتأهيل العملاء المحتملين ومتابعتهم.',
  marketing: 'التسويق الأدائي و SEO: نركز على العملاء والنتيجة التجارية وليس المشاهدات فقط.',
  website: 'المواقع الذكية: موقع مربوط بإدارة العملاء والأتمتة ويخدم المبيعات فعلاً.',
  social: 'أنظمة المحتوى: استراتيجية ونشر ومتابعة تخدم الهدف التجاري.'
};

return { query, services };

return {
  rules: [
    'Business only. Redirect off-topic questions back to Ziyada services.',
    'Short voice-safe replies only.',
    'Ask one question at a time.',
    'Collect numbers digit by digit and repeat them digit by digit.',
    'Do not mix Arabic and English when reading numbers unless requested.',
    'Guide toward consultation booking or qualified lead capture.'
  ]
};
